// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  Platform,
  useWindowDimensions,
} from "react-native";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  const { width } = useWindowDimensions();

  const isSmall = width < 420;
  const isMobile = width < 768;
  const isDesktop = width >= 1024;

  const containerMaxWidth = isDesktop ? 520 : isMobile ? 520 : "100%";

  const [query, setQuery] = useState(
    "Total borne 10 entre\nenfant noir chez le boss"
  );

  const resolved = useMemo(
    () => ({
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    }),
    []
  );

  const onResolve = () => console.log("Resolve:", query);
  const onNavigate = () =>
    console.log("Navigate:", resolved.latitude, resolved.longitude);

  return (
    <SafeAreaView style={styles.safe}>
      {/* ✅ No ScrollView: screen must not scroll */}
      <View style={styles.page}>
        <View style={[styles.container, { maxWidth: containerMaxWidth }]}>
          {/* Header (DO NOT TOUCH) */}
          <View style={styles.headerArea}>
            <View style={styles.headerRow}>
              <Image
                source={nalicoreLogo}
                style={[styles.logo, { width: isSmall ? 165 : 195 }]}
                resizeMode="contain"
              />
              <Text
                style={[
                  styles.tagline,
                  {
                    fontSize: isSmall ? 14 : 15,
                    lineHeight: isSmall ? 19 : 20,
                  },
                ]}
                numberOfLines={2}
              >
                Natural Address{"\n"}Location Infrastructure
              </Text>
            </View>
          </View>

          {/* Body */}
          <View style={styles.body}>
            {/* ✅ Search + Resolve (UPDATED ONLY THIS SECTION) */}
            <View style={styles.searchOuter}>
              <View style={styles.searchBar}>
                <View style={styles.searchLeft}>
                  <Text style={styles.searchIcon}>⌕</Text>

                  <TextInput
                    value={query}
                    onChangeText={setQuery}
                    style={[
                      styles.searchInput,
                      {
                        fontSize: isSmall ? 16 : 17,
                        lineHeight: isSmall ? 22 : 24,
                      },
                    ]}
                    placeholder="Type an address…"
                    placeholderTextColor="rgba(15,23,42,0.28)" // ✅ light gray
                    multiline
                    numberOfLines={2}
                    scrollEnabled={false}
                    textAlignVertical="center"
                    underlineColorAndroid="transparent"
                  />
                </View>

                <View style={styles.searchDivider} />

                <TouchableOpacity
                  activeOpacity={0.92}
                  style={[styles.resolveBtn, { width: isSmall ? 132 : 150 }]}
                  onPress={onResolve}
                >
                  <Text
                    style={[
                      styles.resolveText,
                      { fontSize: isSmall ? 17 : 18 },
                    ]}
                  >
                    Resolve
                  </Text>
                </TouchableOpacity>
              </View>
            </View>

            {/* Card (unchanged) */}
            <View style={styles.card}>
              <Text style={[styles.cardTitle, { fontSize: isSmall ? 20 : 22 }]}>
                Resolved Address
              </Text>

              <Row label="Quartier:" value={resolved.quartier} isSmall={isSmall} />
              <Row label="Secteur:" value={resolved.secteur} isSmall={isSmall} />
              <Row
                label="Sous-secteur:"
                value={resolved.sousSecteur}
                isSmall={isSmall}
              />
              <Row label="Entrée:" value={resolved.entree} isSmall={isSmall} />
              <Row label="Lieu:" value={resolved.lieu} isSmall={isSmall} />

              <View style={styles.row}>
                <Text style={[styles.label, { fontSize: isSmall ? 14 : 15 }]}>
                  BANOC:
                </Text>
                <View style={styles.banocPill}>
                  <Text style={styles.banocText}>{resolved.banoc}</Text>
                </View>
              </View>

              <Row
                label="Latitude:"
                value={Number(resolved.latitude).toFixed(5)}
                isSmall={isSmall}
              />
              <Row
                label="Longitude:"
                value={Number(resolved.longitude).toFixed(5)}
                isSmall={isSmall}
              />

              <TouchableOpacity
                activeOpacity={0.9}
                style={styles.navBtn}
                onPress={onNavigate}
              >
                <PinIcon />
                <Text style={[styles.navText, { fontSize: isSmall ? 18 : 19 }]}>
                  Navigate to Location
                </Text>
              </TouchableOpacity>
            </View>
          </View>
        </View>
      </View>
    </SafeAreaView>
  );
}

function Row({ label, value, isSmall }) {
  return (
    <View style={styles.row}>
      <Text style={[styles.label, { fontSize: isSmall ? 14 : 15 }]}>{label}</Text>
      <Text style={[styles.value, { fontSize: isSmall ? 15 : 16 }]} numberOfLines={1}>
        {value}
      </Text>
    </View>
  );
}

function PinIcon() {
  return (
    <View style={styles.pinWrap}>
      <View style={styles.pinCircle}>
        <View style={styles.pinHead} />
        <View style={styles.pinStem} />
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#E9ECF6" },

  // header touches top/left/right
  page: {
    flex: 1,
    alignItems: "center",
    paddingTop: 0,
    paddingHorizontal: 0,
  },

  container: {
    width: "100%",
    paddingHorizontal: 0,
    paddingTop: 0,
  },

  // Header (unchanged)
  headerArea: {
    width: "100%",
    paddingVertical: 10,
    paddingHorizontal: 14,
    borderRadius: 0,
    backgroundColor: "rgba(255,255,255,0.55)",
    borderBottomWidth: 1,
    borderColor: "rgba(15,23,42,0.06)",
    marginBottom: 12,
  },

  headerRow: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    gap: 12,
  },

  logo: { height: 48 },

  tagline: {
    textAlign: "right",
    color: "rgba(15, 23, 42, 0.65)",
    fontWeight: "500",
    maxWidth: 240,
  },

  body: {
    paddingHorizontal: 14,
    paddingBottom: 14,
  },

  /* =========================
     ✅ SEARCH SECTION (UPDATED)
     ========================= */

  // outer wrapper adds the soft shadow/glow like your target screenshot
  searchOuter: {
    borderRadius: 18,
    marginBottom: 12,
    ...Platform.select({
      ios: {
        shadowColor: "#1E2A4A",
        shadowOpacity: 0.10,
        shadowRadius: 20,
        shadowOffset: { width: 0, height: 14 },
      },
      android: { elevation: 3 },
    }),
  },

  searchBar: {
    width: "100%",
    height: 74,
    borderRadius: 18,
    overflow: "hidden",
    flexDirection: "row",

    // lighter/cleaner like the target
    backgroundColor: "rgba(255,255,255,0.78)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.10)",
  },

  searchLeft: {
    flex: 1,
    minWidth: 0,
    paddingLeft: 48,
    paddingRight: 12,
    justifyContent: "center",
    backgroundColor: "rgba(255,255,255,0.86)", // slightly lighter than overall
  },

  searchIcon: {
    position: "absolute",
    left: 16,
    top: 28,
    fontSize: 20,
    color: "rgba(15, 23, 42, 0.35)",
  },

  searchInput: {
    minWidth: 0,
    fontWeight: "600",
    color: "#0F172A",
    paddingVertical: 0,
    height: 74,
    ...(Platform.OS === "web" ? { outlineStyle: "none" } : null),
